"""
This module contains the Board class, which represents the 8x8 board.
"""

class Piece:
    def __init__(self, color):
        self.color = color


class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        colors = ["red", "black"]
        for i, row in enumerate(range(0, 32, 16)):
            color = colors[i % 2]
            for j in range(row, row + 8, 2):
                if i < 4:
                    self.board[j // 8][j % 8] = Piece(color)
                elif i > 3 and color == "black":
                    self.board[j // 8][j % 8] = Piece(color)

    def print_board(self):
        for row in self.board:
            print(" ".join(piece.color if piece else " . " for piece in row))
```

